    `completion   ${pad(Math.round(progress))}%`,
    `drift        ${drift}db`,
    `tension      ${tension}db`,
    `carrier      ${SIGNALS[frame % SIGNALS.length]}`,
    `vector       ${pad(48 + (frame % 37), 2)}`,
  ].join('\n');
}

