  --sidebar-primary: oklch(0.92 0.01 250);
  --sidebar-primary-foreground: oklch(0.12 0.01 250);
  --sidebar-accent: oklch(0.22 0.01 250);
  --sidebar-accent-foreground: oklch(0.95 0.005 90);
  --sidebar-border: oklch(0.25 0.01 250);
  --sidebar-ring: oklch(0.55 0.02 250);

  /* ASCII Design Tokens - Dark */
  --ascii-border: oklch(0.30 0.01 250);
