}

/* ═══════════════════════════════════════════════════════════════════════════
   BASE LAYER
   ═══════════════════════════════════════════════════════════════════════════ */
@layer base {
  * {
    @apply border-border outline-ring/50;
  }

  body {
    @apply bg-background text-foreground;
    font-feature-settings: "rlig" 1, "calt" 1;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    max-width: 100%;
  }

  /* Smooth scroll with reduced motion support */
  html {
    scroll-behavior: smooth;
    max-width: 100%;
  }

  @media (prefers-reduced-motion: reduce) {
    html {
      scroll-behavior: auto;
    }

    *,
    *::before,
    *::after {
      animation-duration: 0.01ms !important;
      animation-iteration-count: 1 !important;
      transition-duration: 0.01ms !important;
      scroll-behavior: auto !important;
    }
  }
}

/* ═══════════════════════════════════════════════════════════════════════════
   ASCII DESIGN COMPONENTS
   ═══════════════════════════════════════════════════════════════════════════ */

/* ASCII Border System */
.ascii-border {
  border: 1px solid var(--ascii-border);
  position: relative;
}

.ascii-border::before {
  content: '+';
  position: absolute;
  top: -0.5rem;
  left: -0.5rem;
  font-family: var(--font-mono);
  font-size: 0.75rem;
  color: var(--ascii-text);
  background: var(--background);
  padding: 0 0.25rem;
}

/* ASCII Grid Overlay */
.ascii-grid {
  background-image: 
    linear-gradient(var(--ascii-border) 1px, transparent 1px),
    linear-gradient(90deg, var(--ascii-border) 1px, transparent 1px);
  background-size: 20px 20px;
  background-position: -1px -1px;
}

/* ASCII Divider */
.ascii-divider {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-family: var(--font-mono);
  font-size: 0.75rem;
  color: var(--ascii-text);
  letter-spacing: 0.05em;
}

.ascii-divider::before,
.ascii-divider::after {
  content: '';
  flex: 1;
  height: 1px;
  background: var(--ascii-border);
}

/* ASCII Section Marker */
.ascii-marker {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  font-family: var(--font-mono);
  font-size: 0.625rem;
  text-transform: uppercase;
  letter-spacing: 0.2em;
  color: var(--muted-foreground);
}

.ascii-marker::before {
  content: '[';
  color: var(--ascii-accent);
}

.ascii-marker::after {
  content: ']';
  color: var(--ascii-accent);
}

/* Evidence Grid */
.evidence-grid {
  display: grid;
  gap: 1px;
  background: var(--ascii-border);
  border: 1px solid var(--ascii-border);
}

.evidence-grid > * {
  background: var(--background);
  padding: 1rem;
}

/* Typewriter Effect */
@keyframes typewriter {
  from { width: 0; }
  to { width: 100%; }
}

@keyframes blink {
  50% { border-color: transparent; }
}

.typewriter {
  overflow: hidden;
  white-space: nowrap;
  border-right: 2px solid var(--foreground);
  animation: 
    typewriter 2s steps(40) 1s 1 normal both,
    blink 0.75s step-end infinite;
}

/* ASCII Noise Texture */
.noise-overlay {
  position: fixed;
  inset: 0;
  z-index: 9999;
  pointer-events: none;
  opacity: 0.015;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E");
}

/* ═══════════════════════════════════════════════════════════════════════════
   EDITORIAL TYPOGRAPHY
   ═══════════════════════════════════════════════════════════════════════════ */

/* Editorial Title */
.editorial-title {
  font-size: clamp(1.75rem, 8vw, 3.5rem);
  font-weight: 700;
  line-height: 1.1;
  letter-spacing: -0.02em;
}

/* Editorial Subtitle */
.editorial-subtitle {
  font-size: clamp(1.125rem, 2vw, 1.25rem);
  font-weight: 400;
  line-height: 1.6;
  color: var(--muted-foreground);
}

/* Reading Content */
.reading-content {
  font-size: 1.0625rem;
  line-height: 1.75;
  max-width: 65ch;
}

.reading-content p {
  margin-bottom: 1.5em;
}

.reading-content h2 {
  font-size: 1.5rem;
  font-weight: 600;
  margin-top: 2em;
  margin-bottom: 0.75em;
}

.reading-content h3 {
  font-size: 1.25rem;
  font-weight: 600;
  margin-top: 1.75em;
  margin-bottom: 0.5em;
}

.reading-content blockquote {
  border-left: 2px solid var(--ascii-border);
  padding-left: 1.5rem;
  margin: 1.5rem 0;
  font-style: italic;
  color: var(--muted-foreground);
}

.reading-content code {
  font-family: var(--font-mono);
  font-size: 0.9em;
  background: var(--muted);
  padding: 0.125rem 0.375rem;
  border-radius: 0.25rem;
}

.reading-content pre {
  background: var(--muted);
  padding: 1rem 1.25rem;
  border-radius: 0.5rem;
  overflow-x: auto;
  margin: 1.5rem 0;
}

.reading-content pre code {
  background: none;
  padding: 0;
}

/* ═══════════════════════════════════════════════════════════════════════════
   INTERACTIVE ELEMENTS
   ═══════════════════════════════════════════════════════════════════════════ */

/* Proof Card */
.proof-card {
  position: relative;
  padding: 1.5rem;
  border: 1px solid var(--border);
  transition: all 0.2s ease-out;
}

.proof-card:hover {
  border-color: var(--ascii-accent);
  transform: translateY(-2px);
}

.proof-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 3px;
  height: 100%;
  background: linear-gradient(180deg, var(--primary) 0%, transparent 100%);
  opacity: 0;
  transition: opacity 0.2s ease-out;
}

.proof-card:hover::before {
  opacity: 1;
}

/* Navigation Link */
.nav-link {
  position: relative;
  padding: 0.5rem 1rem;
  font-size: 0.875rem;
  font-weight: 500;
  color: var(--muted-foreground);
  transition: color 0.15s ease;
}

.nav-link:hover {
  color: var(--foreground);
}

.nav-link::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 50%;
  width: 0;
  height: 1px;
  background: var(--foreground);
  transition: all 0.2s ease;
  transform: translateX(-50%);
}

.nav-link:hover::after,
.nav-link.active::after {
  width: calc(100% - 2rem);
}

/* CTA Button - ASCII / Terminal Style */
.cta-button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  padding: 0.75rem 1.5rem;
  font-size: 0.8125rem;
  font-weight: 600;
  font-family: var(--font-mono);
  background: var(--primary);
  color: var(--primary-foreground);
  border: 1px solid var(--primary);
  border-radius: 0;
  cursor: pointer;
  transition: all 0.15s ease;
  position: relative;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  box-shadow: 2px 2px 0 var(--border);
}

.dark .cta-button {
  background: transparent;
  color: var(--primary);
  border-color: var(--primary);
  box-shadow: 2px 2px 0 rgba(255, 255, 255, 0.1);
}

.cta-button::before {
  content: '[';
  margin-right: 0.25rem;
  opacity: 0.5;
}

.cta-button::after {
  content: ']';
  margin-left: 0.25rem;
  opacity: 0.5;
}

.cta-button:hover {
  transform: translate(-1px, -1px);
  box-shadow: 4px 4px 0 var(--primary);
  background: var(--primary);
  color: var(--primary-foreground);
}

.dark .cta-button:hover {
  background: var(--primary);
  color: var(--primary-foreground);
  box-shadow: 4px 4px 0 rgba(255, 255, 255, 0.2);
}

.cta-button:active {
  transform: translate(1px, 1px);
  box-shadow: 1px 1px 0 var(--primary);
}

/* Ghost Button */
.ghost-button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  padding: 0.875rem 1.75rem;
  font-size: 0.875rem;
  font-weight: 500;
  background: transparent;
  color: var(--foreground);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  cursor: pointer;
  transition: all 0.15s ease;
}

.ghost-button:hover {
  background: var(--muted);
  border-color: var(--ascii-accent);
}

/* ═══════════════════════════════════════════════════════════════════════════
   LAYOUT UTILITIES
   ═══════════════════════════════════════════════════════════════════════════ */

/* Editorial Container */
.editorial-container {
  width: 100%;
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 clamp(1rem, 4vw, 2rem);
}

/* Content Container */
.content-container {
  width: 100%;
  max-width: 720px;
  margin: 0 auto;
  padding: 0 clamp(1rem, 4vw, 2rem);
}

/* Section Spacing */
.section-spacing {
  padding: var(--section-gap) 0;
}

/* ═══════════════════════════════════════════════════════════════════════════
   ANIMATIONS
   ═══════════════════════════════════════════════════════════════════════════ */

@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes slideInLeft {
  from {
    opacity: 0;
    transform: translateX(-20px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes slideInRight {
  from {
    opacity: 0;
    transform: translateX(20px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

.animate-fade-in {
  animation: fadeIn 0.5s ease-out forwards;
}

.animate-slide-left {
  animation: slideInLeft 0.5s ease-out forwards;
}

.animate-slide-right {
  animation: slideInRight 0.5s ease-out forwards;
}

/* Stagger Animation */
.stagger-1 { animation-delay: 0.1s; }
.stagger-2 { animation-delay: 0.2s; }
.stagger-3 { animation-delay: 0.3s; }
.stagger-4 { animation-delay: 0.4s; }
.stagger-5 { animation-delay: 0.5s; }

/* ═══════════════════════════════════════════════════════════════════════════
   SCROLL PROGRESS
   ═══════════════════════════════════════════════════════════════════════════ */

.scroll-progress {
  position: fixed;
